#include <stdlib.h>

void** allocate2DMatrix(int rows, int cols) {
    if (rows <= 0 || cols <= 0) {
        return NULL;
    }

    // Allocate memory for the array of pointers
    void** matrix = (void**)malloc(rows * sizeof(void*));
    if (matrix == NULL) {
        return NULL;
    }

    // Allocate memory for each row
    for (int i = 0; i < rows; ++i) {
        matrix[i] = malloc(cols * sizeof(double)); // Assuming double as the element type
        if (matrix[i] == NULL) {
            // Free previously allocated memory on failure
            for (int j = 0; j < i; ++j) {
                free(matrix[j]);
            }
            free(matrix);
            return NULL;
        }
    }

    return matrix;
}

void free2DMatrix(void** matrix, int rows) {
    if (matrix == NULL || rows <= 0) {
        return;
    }

    // Free each row
    for (int i = 0; i < rows; ++i) {
        free(matrix[i]);
    }

    // Free the array of pointers
    free(matrix);
}